"""
Treinador do modelo LSTM para previsão de demanda energética.
Autor: Jariane Santos
Data: 2026
"""

from src.prediction.lstm_model import EnergyDemandLSTM
from src.prediction.data_preprocessing import DataPreprocessor
import pandas as pd
import numpy as np
from typing import Optional, Tuple
from pathlib import Path
import joblib

class LSTMTrainer:
    """
    Classe para treinar o modelo LSTM de previsão de demanda energética.
    """

    def __init__(
        self,
        input_window: int = 24,
        forecast_horizon: int = 6,
        test_size: float = 0.2,
        random_state: int = 42,
        model_dir: str = "models"
    ):
        """
        Inicializa o treinador.

        Args:
            input_window (int): Janela de entrada para o LSTM.
            forecast_horizon (int): Horizonte de previsão.
            test_size (float): Proporção de dados para teste (0-1).
            random_state (int): Semente aleatória para reprodutibilidade.
            model_dir (str): Diretório para salvar o modelo.
        """
        self.input_window = input_window
        self.forecast_horizon = forecast_horizon
        self.test_size = test_size
        self.random_state = random_state
        self.model_dir = Path(model_dir)
        self.model_dir.mkdir(parents=True, exist_ok=True)

        self.preprocessor = DataPreprocessor()
        self.model = EnergyDemandLSTM(
            input_window=input_window,
            forecast_horizon=forecast_horizon,
            model_dir=model_dir
        )

    def train(
        self,
        data_path: str,
        target_column: str = "power_demand",
        date_column: str = "timestamp",
        save_model: bool = True
    ) -> Tuple[dict, dict]:
        """
        Treina o modelo LSTM.

        Args:
            data_path (str): Caminho para o arquivo de dados.
            target_column (str): Coluna alvo para previsão.
            date_column (str): Coluna de data/hora.
            save_model (bool): Se deve salvar o modelo treinado.

        Returns:
            Tuple[dict, dict]: Histórico de treinamento e métricas de avaliação.
        """
        # Carrega e pré-processa os dados
        df = self.preprocessor.load_data(data_path, date_column)
        df = self.preprocessor.add_time_features(df, date_column)
        df = self.preprocessor.handle_missing_values(df)

        # Normaliza os dados
        df, scaler = self.preprocessor.normalize(df)

        # Cria sequências
        X, y = self.preprocessor.create_sequences(
            df, target_column, self.input_window, self.forecast_horizon
        )

        # Divide em treinamento e teste
        split_idx = int(len(X) * (1 - self.test_size))
        X_train, X_test = X[:split_idx], X[split_idx:]
        y_train, y_test = y[:split_idx], y[split_idx:]

        # Treina o modelo
        history = self.model.train(
            X_train, y_train,
            X_val=X_test, y_val=y_test,
            save_model=save_model
        )

        # Avalia o modelo
        metrics = self.model.evaluate(X_test, y_test)

        return history, metrics

    def predict(
        self,
        data_path: str,
        steps: int = 6,
        target_column: str = "power_demand",
        date_column: str = "timestamp"
    ) -> np.ndarray:
        """
        Faz previsões usando o modelo treinado.

        Args:
            data_path (str): Caminho para o arquivo de dados.
            steps (int): Número de passos à frente para prever.
            target_column (str): Coluna alvo para previsão.
            date_column (str): Coluna de data/hora.

        Returns:
            np.ndarray: Previsões de demanda energética.
        """
        # Carrega e pré-processa os dados
        df = self.preprocessor.load_data(data_path, date_column)
        df = self.preprocessor.add_time_features(df, date_column)
        df = self.preprocessor.handle_missing_values(df)

        # Normaliza os dados
        df, _ = self.preprocessor.normalize(df)

        # Cria sequências
        X, _ = self.preprocessor.create_sequences(
            df, target_column, self.input_window, self.forecast_horizon
        )

        # Faz previsões
        predictions = self.model.predict(X[-1:], steps=steps)

        return predictions.flatten()